def is_prime(n):
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

primes = []
num = 2
while len(primes) < 17:
    if is_prime(num):
        primes.append(num)
    num += 1

print(f"First {len(primes)} primes: {primes}")
print(f"The 17th prime is: {primes[16]}")

